async function initializeDatabase() {
  if (!db) {
    const sqlite3InitModule = await import('@sqlite.org/sqlite-wasm').then(m => m.default)
    // @ts-expect-error sqlite3ApiConfig is not defined in the module
    globalThis.sqlite3ApiConfig = {
      // overriding default log function allows to avoid error when logger are dropped in build.
      // For example `nuxt-security` module drops logger in production build by default.
      silent: true,
      debug: (...args: unknown[]) => console.debug(...args),
      warn: (...args: unknown[]) => {
        if (String(args[0]).includes('OPFS sqlite3_vfs')) {
          return
        }
        console.warn(...args)
      },
      error: (...args: unknown[]) => console.error(...args),
      log: (...args: unknown[]) => console.log(...args),
    }
    const sqlite3 = await sqlite3InitModule()
    db = new sqlite3.oo1.DB()
  }
  return db
}

async (event) => {
  const collection = getRouterParam(event, 'collection')! || event.path?.split('/')?.[2] || ''
  setHeader(event, 'Content-Type', 'text/plain')

  const ASSETS = event?.context?.cloudflare?.env.ASSETS || process.env.ASSETS
  if (ASSETS) {
    const config = event?.context?.nitro?.runtimeConfig
    const url = new URL(event.context.cloudflare?.request?.url || 'http://localhost')
    url.pathname = `${config?.app?.baseURL || '/'}dump.${collection}.sql`
    return await ASSETS.fetch(url).then((r: Response) => r.text())
  }

  return await useStorage().getItem(`build:content:raw:dump.${collection}.sql`) || ''
}

export function onDevtoolsHostClientConnected(fn: (client: NuxtDevtoolsHostClient) => void) {
  fns.push(fn)

  if (typeof window === 'undefined')
    return

  // eslint-disable-next-line ts/ban-ts-comment
  // @ts-ignore injection
  if (window.__NUXT_DEVTOOLS_HOST__) {
    // eslint-disable-next-line ts/ban-ts-comment
    // @ts-ignore injection
    fns.forEach(fn => fn(window.__NUXT_DEVTOOLS_HOST__))
  }

  Object.defineProperty(window, '__NUXT_DEVTOOLS_HOST__', {
    set(value) {
      if (value)
        fns.forEach(fn => fn(value))
    },
    get() {
      return clientRef!.value
    },
    configurable: true,
  })

  return () => {
    fns.splice(fns.indexOf(fn), 1)
  }
}

