    const body = JSON.stringify(mergedSeoMetaOptions, null, 2)
      .replace(JSON_KEY_RE, '$1:')
      .replace(DOUBLE_QUOTE_RE, '\'')

    lines.push(`useSeoMeta(${body})`)
  }

