export function useComponents() {
  const client = useClient()
  const serverComponents = useAsyncState('getComponents', () => rpc.getComponents())

  const globalComponents = computed(() =>
    Object
      .entries(client.value?.nuxt?.vueApp._context.components || {})
      .map(([key]) => ({
        pascalName: key,
        global: true,
      } as unknown as Component))
      // filter out lazy components
      .filter(i => !LAZY_COMPONENT_RE.test(i.pascalName))
      // dedupe server components
      .filter(i => !serverComponents.value || [].some((s: any) => s.pascalName === i.pascalName)))

  return computed(() => [
    ...globalComponents.value,
    ...serverComponents.value || [],
  ].sort((a: any, b: any) => a.pascalName.localeCompare(b.pascalName)))
}

export function useObjectStorage<T>(key: string, initial: T, listenToStorage = true): Ref<T> {
  const raw = localStorage.getItem(key)
  const data = ref(raw ? JSON.parse(raw) : initial)

  for (const key in initial) {
    if (data.value[key] === undefined)
      data.value[key] = initial[key]
  }

  let updating = false
  let wrote = ''

  watch(data, (value) => {
    if (updating)
      return
    wrote = JSON.stringify(value)
    localStorage.setItem(key, wrote)
  }, { deep: true, flush: 'post' })

  if (listenToStorage) {
    useEventListener(window, 'storage', (e: StorageEvent) => {
      if (e.key === key && e.newValue && e.newValue !== wrote) {
        updating = true
        data.value = JSON.parse(e.newValue)
        updating = false
      }
    })
  }

  return data
}

async function _resolvePathType (path: string, opts: ResolvePathOptions = {}, skipFs = false): Promise<PathResolution | undefined> {
  if (opts?.virtual && existsInVFS(path)) {
    return {
      path,
      type: 'file',
      virtual: true,
    }
  }

  if (skipFs) {
    return
  }

  const fd = await fsp.open(path, 'r').catch(() => null)
  try {
    const stats = await fd?.stat()
    if (stats) {
      return {
        path,
        type: stats.isFile() ? 'file' : 'dir',
        virtual: false,
      }
    }
  } finally {
    fd?.close()
  }
}

export function renderPayloadJsonScript (opts: { ssrContext: NuxtSSRContext, data?: any, src?: string }): Script[] {
  const contents = opts.data ? encodeForwardSlashes(stringify(opts.data, opts.ssrContext['~payloadReducers'])) : ''
  const payload: Script = {
    'type': 'application/json',
    'innerHTML': contents,
    'data-nuxt-data': appId,
    'data-ssr': !(NUXT_NO_SSR || opts.ssrContext.noSSR),
  }
  if (!multiApp) {
    payload.id = '__NUXT_DATA__'
  }
  if (opts.src) {
    payload['data-src'] = opts.src
  }
  const config = uneval(opts.ssrContext.config)
  return [
    payload,
    {
      innerHTML: multiApp
        ? `window.__NUXT__=window.__NUXT__||{};window.__NUXT__[${JSON.stringify(appId)}]={config:${config}}`
        : `window.__NUXT__={};window.__NUXT__.config=${config}`,
    },
  ]
}

ssrRender (ctx: any, push: any, parent: any) {
  if (ctx.ssrFailed) {
    const { fallback, placeholder } = ctx.$slots
    if (fallback || placeholder) {
      ssrRenderSlot(ctx.$slots, fallback ? 'fallback' : 'placeholder', {}, null, push, parent)
    } else {
      const content = ctx.placeholder || ctx.fallback
      const tag = sanitizeTag(ctx.placeholderTag || ctx.fallbackTag, 'div')
      push(`<${tag}${ssrRenderAttrs(ctx.$attrs)}>${ssrInterpolate(content)}</${tag}>`)
    }
  } else {
    // push Fragment markup
    push('<!--[-->')
    push(ctx.ssrVNodes.getBuffer())
    push('<!--]-->')
  }
}

export function clearNuxtState (
  keys?: string | string[] | ((key: string) => boolean),
  opts?: ClearNuxtStateOptions,
): void {
  const reset = opts?.reset ?? useStateDefaults.resetOnClear

  const nuxtApp = useNuxtApp()
  const _allKeys = Object.keys(nuxtApp.payload.state)
    .filter(key => key.startsWith(useStateKeyPrefix))
    .map(key => key.substring(useStateKeyPrefix.length))

  const _keys: string[] = !keys
    ? _allKeys
    : typeof keys === 'function'
      ? _allKeys.filter(keys)
      : toArray(keys)

  for (const _key of _keys) {
    const key = useStateKeyPrefix + _key
    if (key in nuxtApp.payload.state) {
      if (reset && nuxtApp._state[key]) {
        nuxtApp.payload.state[key] = nuxtApp._state[key]._default()
      } else {
        delete nuxtApp.payload.state[key]
      }
    }
  }
}

