function iframeContentHtml(uiUrl: string | undefined) {
  return [
    '<html><head><script>',
    `(${function redirect(uiUrl: string, provider: string) {
      if (typeof window === 'undefined') return

      if (!uiUrl) return

      if (provider === 'stackblitz') {
        const url = new URL(window.location.href)
        const newUrl = new URL(uiUrl)
        newUrl.host = url.host.replace(/--\d+--/, `--${newUrl.port}--`)
        newUrl.protocol = url.protocol
        newUrl.port = url.port
        uiUrl = newUrl.toString()
      }

      window.location.replace(uiUrl)
    }})(${JSON.stringify(uiUrl)}, ${JSON.stringify(provider)})`,
    '</script></head></html>',
  ].join('\n')
}

export function getDependencies(answers: WizardAnswers): string[] {
  const dependencies: string[] = []

  if (answers.testingScope.includes('unit') || answers.testingScope.includes('runtime')) {
    dependencies.push('vitest', '@vue/test-utils')

    if (answers.domEnvironment) {
      dependencies.push(answers.domEnvironment)
    }

    if (answers.browserMode) {
      dependencies.push('@vitest/browser-playwright')
    }
  }

  if (answers.e2eRunner === 'playwright') {
    dependencies.push('@playwright/test', 'playwright-core')
  }
  else if (answers.e2eRunner === 'cucumber') {
    dependencies.push('@cucumber/cucumber')
  }
  else if (answers.e2eRunner === 'jest') {
    dependencies.push('@jest/globals')
  }

  if (answers.coverage) {
    dependencies.push('@vitest/coverage-v8')
  }

  return dependencies
}

function onUpdate(files: File[], reset = false) {
  if (props.multiple) {
    if (reset) {
      modelValue.value = files as (M extends true ? File[] : File) | null
    } else {
      const existingFiles = (modelValue.value as File[]) || []
      modelValue.value = [...existingFiles, ...(files || [])] as (M extends true ? File[] : File) | null
    }
  } else {
    modelValue.value = (files?.[0] ?? null) as (M extends true ? File[] : File) | null
  }

  // @ts-expect-error - 'target' does not exist in type 'EventInit'
  const event = new Event('change', { target: { value: modelValue.value } })
  emits('change', event)
  emitFormChange()
  emitFormInput()
}

function buildTree(items: { label: string }[]): TreeNode[] {
  const map = new Map<string, TreeNode>()
  const root: TreeNode[] = []

  items.forEach((item) => {
    const parts = item.label.split('/')
    let path = ''

    parts.forEach((part, i) => {
      path = path ? `${path}/${part}` : part

      if (!map.has(path)) {
        const node = { label: part, path, ...(i < parts.length - 1 && { children: [] }) }
        map.set(path, node)

        if (i === 0) {
          root.push(node)
        } else {
          map.get(parts.slice(0, i).join('/'))?.children?.push(node)
        }
      }
    })
  })

  const sort = (nodes: TreeNode[]): TreeNode[] =>
    nodes.sort((a, b) =>
      !!a.children === !!b.children ? a.label.localeCompare(b.label) : b.children ? 1 : -1
    ).map(n => ({ ...n, children: n.children && sort(n.children) }))

  return sort(root)
}

