    labelKey: props.labelKey,
    valueKey: props.valueKey,
    by: props.by
  })
}

function convertKeyToCode(key: string): string {
  // Handle single letters
  if (/^[a-z]$/i.test(key)) {
    return `Key${key.toUpperCase()}`
  }
  // Handle digits
  if (/^\d$/.test(key)) {
    return `Digit${key}`
  }
  // Handle function keys
  if (/^f\d+$/i.test(key)) {
    return key.toUpperCase()
  }
  // Handle common special keys
  const specialKeys: Record<string, string> = {
    space: 'Space',
    enter: 'Enter',
    escape: 'Escape',
    tab: 'Tab',
    backspace: 'Backspace',
    delete: 'Delete',
    arrowup: 'ArrowUp',
    arrowdown: 'ArrowDown',
    arrowleft: 'ArrowLeft',
    arrowright: 'ArrowRight'
  }
  return specialKeys[key.toLowerCase()] || key
}

(obj: unknown): string => {
  // Stringify function body
  if (typeof obj === 'function') {
    return obj.toString()
  }

  // Run recursively on objects and arrays
  if (typeof obj === 'object' && obj !== null) {
    if (Array.isArray(obj)) {
      return `[${obj.map(serializeConfig).join(', ')}]`
    } else if (obj === null) {
      // To make typescript happy
      return 'null'
    } else {
      return `{${Object.entries(obj).map(([key, value]) => `${serializeConfig(key)}: ${serializeConfig(value)}`).join(', ')}}`
    }
  }

  return JSON.stringify(obj)
}

