export function createContext(userOptions: NuxtI18nOptions, nuxt: Nuxt): I18nNuxtContext {
  const options = userOptions as Required<NuxtI18nOptions>

  const i18nLayers: LayerWithI18n[] = []
  for (const l of nuxt.options._layers) {
    const i18n = getLayerI18n(l)
    if (!i18n) { continue }
    const i18nDir = resolve(l.config.rootDir, i18n.restructureDir ?? 'i18n')
    const i18nDetector = i18n.experimental?.localeDetector ? resolver.resolve(i18nDir, i18n.experimental.localeDetector) : undefined
    i18nLayers.push({ config: l, i18n, i18nDir, i18nDetector })
  }

  return {
    options,
    resolver,
    userOptions,
    distDir,
    runtimeDir,
    i18nLayers,
    localeInfo: undefined!,
    localeCodes: undefined!,
    normalizedLocales: undefined!,
    vueI18nConfigPaths: undefined!,
    fullStatic: undefined!,
    localeHashes: undefined!,
  }
}

function generateInterface(obj: Record<string, unknown>, indentLevel = 1) {
  const indent = '  '.repeat(indentLevel)
  let str = ''

  for (const key in obj) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) { continue }

    if (isObject(obj[key]) && obj[key] !== null && !isArray(obj[key])) {
      str += `${indent}"${key}": {\n`
      str += generateInterface(obj[key] as Record<string, unknown>, indentLevel + 1)
      str += `${indent}};\n`
    } else {
      let propertyType = isArray(obj[key]) ? 'unknown[]' : typeof obj[key]
      if (isFunction(propertyType)) {
        propertyType = '() => string'
      }
      str += `${indent}"${key}": ${propertyType};\n`
    }
  }
  return str
}

(event: H3Event | undefined, config: { cookieKey: string }, nuxtApp?: NuxtApp) => {
  if (import.meta.server && !event) {
    throw new Error('H3Event is required for server-side locale detection')
  }

  const runtimeI18n = useRuntimeI18n(nuxtApp)

  return {
    cookie: () => getCookieLocale(event, config.cookieKey),
    header: () => (import.meta.server ? getHeaderLocale(event) : undefined),
    navigator: () => (import.meta.client ? getNavigatorLocale(event) : undefined),
    host: (path: string) => getHostLocale(event, path, runtimeI18n.domainLocales),
    route: (path: string | CompatRoute) => getRouteLocale(event, path),
  }
}

export function isExistingNuxtRoute(path: string) {
  if (path === '') { return }
  // TODO: path should not have base url - check if base url is stripped earlier
  // skip nuxt error route - this path is hardcoded within nitro context code in nuxt
  if (path.endsWith('/__nuxt_error')) { return }

  // skip disabled i18n routes - this prevent a redirect if there is a catch all route
  const disabledI18nResolvedMatch = disabledI18nMatcher.resolve({ path }, { path: '/', name: '', matched: [], params: {}, meta: {} })
  if (disabledI18nResolvedMatch.matched.length > 0) {
    return
  }

  const resolvedMatch = matcher.resolve({ path }, { path: '/', name: '', matched: [], params: {}, meta: {} })

  return resolvedMatch.matched.length > 0 ? resolvedMatch : undefined
}

function genLocaleLoaderHMR(localeLoaders: TemplateNuxtI18nOptions['localeLoaders']) {
  const statements: string[] = []

  for (const locale in localeLoaders) {
    for (let i = 0; i < localeLoaders[locale]!.length; i++) {
      const loader = localeLoaders[locale]![i]!
      statements.push(
        [
          `  import.meta.hot.accept("${loader.relative}", async mod => {`,
          //   replace locale loader
          `    localeLoaders["${locale}"][${i}].load = () => Promise.resolve(mod.default)`,
          //   trigger locale messages reload for locale
          `    await useNuxtApp()._nuxtI18n.dev.resetI18nProperties("${locale}")`,
          `  })`,
        ].join('\n'),
      )
    }
  }

  return statements.join('\n\n')
}

export function isVue(id: string, opts: { type?: Array<'template' | 'script' | 'style'> } = {}) {
  // Bare `.vue` file (in Vite)
  const { search } = parseURL(decodeURIComponent(pathToFileURL(id).href))
  if (id.endsWith('.vue') && !search) {
    return true
  }

  if (!search) {
    return false
  }

  const query = parseQuery(search)

  // Component async/lazy wrapper
  if (query.nuxt_component) {
    return false
  }

  // Macro
  if (query.macro && (search === '?macro=true' || !opts.type || opts.type.includes('script'))) {
    return true
  }

  // Non-Vue or Styles
  const type = 'setup' in query ? 'script' : (query.type as 'script' | 'template' | 'style')
  if (!('vue' in query) || (opts.type && !opts.type.includes(type))) {
    return false
  }

  // Query `?vue&type=template` (in Webpack or external template)
  return true
}

export function createStringifyProcessor(options: MDCStringifyOptions = {}) {
  return unified()
    .use(function jsonParser(this: Processor) {
      this.parser = function (root: string) {
        return JSON.parse(root)
      }
    })
    .use(mdcRemark)
    .use(gfm)
    .use(mdc, options?.plugins?.['remark-mdc']?.options || options?.plugins?.remarkMDC?.options || {})
    .use(stringify, {
      bullet: '-',
      emphasis: '*',
      rule: '-',
      listItemIndent: 'one',
      fence: '`',
      fences: true,
      ...options?.plugins?.remarkStringify?.options,
    })
}
